import json
import pytest
from deepeval.dataset import EvaluationDataset
from deepeval.metrics import AnswerRelevancyMetric, FaithfulnessMetric
from deepeval import evaluate

BASELINE_PATH = 'eval_baseline.json'
REGRESSION_TOLERANCE = 0.05  # allow 5% degradation before failing

def run_suite(dataset) -> dict:
    results = evaluate(
        test_cases=dataset,
        metrics=[
            AnswerRelevancyMetric(threshold=0.0),  # threshold=0 to always collect scores
            FaithfulnessMetric(threshold=0.0),
        ],
        print_results=False,
    )
    return {
        m_name: score
        for m_name, score in results.metric_scores.items()
    }

def test_no_regression(golden_dataset):
    try:
        baseline = json.load(open(BASELINE_PATH))
    except FileNotFoundError:
        baseline = None

    current = run_suite(golden_dataset)

    if baseline is None:
        json.dump(current, open(BASELINE_PATH, 'w'))
        pytest.skip('Baseline recorded; run again to check regression')

    for metric, score in current.items():
        base_score = baseline.get(metric, 0.0)
        drop = base_score - score
        assert drop <= REGRESSION_TOLERANCE, (
            f'{metric} regressed: {base_score:.3f} → {score:.3f} (drop={drop:.3f})'
        )
